const firstName = $('Execute Workflow Trigger').first().json.firstName;

const state = {
  step: 0,
  data: {},
  lastUpdated: new Date().toISOString()
};

return [{
  json: {
    state,
    isValid: true,
    isComplete: false,
    responseMessage: `¡Hola ${firstName}! Bienvenido/a a FitAI.\n\nSoy tu asistente personal de nutrición y fitness. Para poder ayudarte de la mejor manera, necesito conocerte un poco.\n\nVamos a empezar con unas preguntas rápidas (toma unos 3 minutos).\n\n¿Cuál es tu género biológico? Esto me ayuda a calcular tus necesidades calóricas con precisión.\n\n1️⃣ Masculino\n2️⃣ Femenino`
  }
}];

const stateRaw = $('Get Onboarding State').first().json.value;
const state = typeof stateRaw === 'string' ? JSON.parse(stateRaw) : stateRaw;
const userText = $('Execute Workflow Trigger').first().json.text ? $('Execute Workflow Trigger').first().json.text.trim() : '';

const step = state.step;
let isValid = false;
let errorMessage = '';
let fieldName = '';
let fieldValue = null;
let nextQuestion = '';

switch (step) {
  case 0: // gender
    fieldName = 'gender';
    if (['1', 'masculino', 'hombre', 'male'].includes(userText.toLowerCase())) {
      fieldValue = 'male'; isValid = true;
    } else if (['2', 'femenino', 'mujer', 'female'].includes(userText.toLowerCase())) {
      fieldValue = 'female'; isValid = true;
    } else {
      errorMessage = 'Por favor responde con 1 (Masculino) o 2 (Femenino).';
    }
    if (isValid) nextQuestion = '¿Cuántos años tienes?';
    break;

  case 1: // age
    fieldName = 'age';
    const age = parseInt(userText);
    if (!isNaN(age) && age >= 14 && age <= 100) {
      fieldValue = age; isValid = true;
      nextQuestion = '¿Cuánto mides? (en centímetros, ej: 170)';
    } else {
      errorMessage = 'Por favor ingresa una edad válida entre 14 y 100 años.';
    }
    break;

  case 2: // height_cm
    fieldName = 'height_cm';
    const height = parseFloat(userText.replace(',', '.'));
    if (!isNaN(height) && height >= 100 && height <= 250) {
      fieldValue = height; isValid = true;
      nextQuestion = '¿Cuánto pesas actualmente? (en kilogramos, ej: 75.5)';
    } else {
      errorMessage = 'Por favor ingresa una estatura válida entre 100 y 250 cm.';
    }
    break;

  case 3: // weight_kg
    fieldName = 'weight_kg';
    const weight = parseFloat(userText.replace(',', '.'));
    if (!isNaN(weight) && weight >= 30 && weight <= 300) {
      fieldValue = weight; isValid = true;
      nextQuestion = '¿Cuál es tu nivel de actividad física?\n\n1️⃣ Sedentario (trabajo de oficina, poco ejercicio)\n2️⃣ Ligeramente activo (ejercicio 1-3 días/semana)\n3️⃣ Moderadamente activo (ejercicio 3-5 días/semana)\n4️⃣ Muy activo (ejercicio 6-7 días/semana)\n5️⃣ Extra activo (atleta o trabajo muy físico)';
    } else {
      errorMessage = 'Por favor ingresa un peso válido entre 30 y 300 kg.';
    }
    break;

  case 4: // activity_level
    fieldName = 'activity_level';
    const activityMap = {'1':'sedentary','2':'lightly_active','3':'moderately_active','4':'very_active','5':'extra_active'};
    if (activityMap[userText]) {
      fieldValue = activityMap[userText]; isValid = true;
      nextQuestion = '¿Cuál es tu nivel de experiencia con el ejercicio?\n\n1️⃣ Principiante (menos de 6 meses)\n2️⃣ Intermedio (6 meses a 2 años)\n3️⃣ Avanzado (más de 2 años)';
    } else {
      errorMessage = 'Por favor responde con un número del 1 al 5.';
    }
    break;

  case 5: // fitness_level
    fieldName = 'fitness_level';
    const fitnessMap = {'1':'beginner','2':'intermediate','3':'advanced'};
    if (fitnessMap[userText]) {
      fieldValue = fitnessMap[userText]; isValid = true;
      nextQuestion = '¿Cuál es tu objetivo principal?\n\n1️⃣ Perder peso\n2️⃣ Ganar músculo\n3️⃣ Mantener peso\n4️⃣ Recomposición corporal';
    } else {
      errorMessage = 'Por favor responde con 1, 2 o 3.';
    }
    break;

  case 6: // goal
    fieldName = 'goal';
    const goalMap = {'1':'lose_weight','2':'gain_muscle','3':'maintain','4':'recomposition'};
    if (goalMap[userText]) {
      fieldValue = goalMap[userText]; isValid = true;
      if (goalMap[userText] === 'lose_weight' || goalMap[userText] === 'gain_muscle') {
        nextQuestion = '¿Cuál es tu peso objetivo? (en kg, ej: 70)\nSi no tienes un número específico, escribe "no sé".';
      } else {
        nextQuestion = '¿Tienes alguna restricción dietética? (ej: vegetariano, vegano, sin gluten)\nSi no tienes ninguna, escribe "ninguna".';
        state.step = 7; // will become 8 after increment
      }
    } else {
      errorMessage = 'Por favor responde con un número del 1 al 4.';
    }
    break;

  case 7: // target_weight
    fieldName = 'target_weight';
    const targetW = parseFloat(userText.replace(',', '.'));
    if (!isNaN(targetW) && targetW >= 30 && targetW <= 300) {
      fieldValue = targetW; isValid = true;
    } else if (['no se', 'no sé', 'skip', 'ninguno'].includes(userText.toLowerCase())) {
      fieldValue = null; isValid = true;
    } else {
      errorMessage = 'Por favor ingresa un peso objetivo válido o escribe "no sé".';
    }
    if (isValid) nextQuestion = '¿Tienes alguna restricción dietética? (ej: vegetariano, vegano, sin gluten)\nSi no tienes ninguna, escribe "ninguna".';
    break;

  case 8: // dietary_restrictions
    fieldName = 'dietary_restrictions';
    fieldValue = userText; isValid = true;
    nextQuestion = '¿Tienes alguna alergia alimentaria?\nSi no tienes ninguna, escribe "ninguna".';
    break;

  case 9: // food_allergies
    fieldName = 'food_allergies';
    fieldValue = userText; isValid = true;
    nextQuestion = '¿Hay alimentos que no te gusten o que prefieras evitar?\nSi no hay ninguno, escribe "ninguno".';
    break;

  case 10: // disliked_foods
    fieldName = 'disliked_foods';
    fieldValue = userText; isValid = true;
    nextQuestion = '¿Tienes alguna lesión o limitación física que deba considerar?\nSi no tienes ninguna, escribe "ninguna".';
    break;

  case 11: // injuries
    fieldName = 'injuries';
    fieldValue = userText; isValid = true;
    nextQuestion = '¿Con qué equipamiento de ejercicio cuentas? (ej: pesas, bandas, gym, nada)\nEscribe lo que tengas disponible.';
    break;

  case 12: // available_equipment
    fieldName = 'available_equipment';
    fieldValue = userText; isValid = true;
    nextQuestion = '¿Cuántos días a la semana puedes entrenar? (número del 1 al 7)';
    break;

  case 13: // training_days_per_week
    fieldName = 'training_days_per_week';
    const days = parseInt(userText);
    if (!isNaN(days) && days >= 1 && days <= 7) {
      fieldValue = days; isValid = true;
      nextQuestion = '¿Cuántas comidas al día prefieres hacer? (número del 2 al 6)';
    } else {
      errorMessage = 'Por favor ingresa un número del 1 al 7.';
    }
    break;

  case 14: // meal_count
    fieldName = 'meal_count';
    const meals = parseInt(userText);
    if (!isNaN(meals) && meals >= 2 && meals <= 6) {
      fieldValue = meals; isValid = true;
      nextQuestion = '¿Cuál es tu presupuesto para ingredientes y comida?\n\n1️⃣ Bajo (económico, ingredientes básicos)\n2️⃣ Medio (variado, ingredientes normales)\n3️⃣ Alto (sin restricciones, ingredientes premium)';
    } else {
      errorMessage = 'Por favor ingresa un número del 2 al 6.';
    }
    break;

  case 15: // budget_level
    fieldName = 'budget_level';
    const budgetMap = {'1':'low','2':'medium','3':'high'};
    if (budgetMap[userText]) {
      fieldValue = budgetMap[userText]; isValid = true;
      nextQuestion = '¡Perfecto! Ya tengo toda la información que necesito.\n\nAquí está un resumen de tu perfil. Escribe "confirmar" para continuar o "corregir" si necesitas cambiar algo.';
    } else {
      errorMessage = 'Por favor responde con 1, 2 o 3.';
    }
    break;

  case 16: // confirmation
    if (['confirmar', 'si', 'sí', 'ok', 'confirm'].includes(userText.toLowerCase())) {
      isValid = true;
      nextQuestion = '¡Excelente! Tu perfil está listo. Ahora voy a calcular tus necesidades calóricas y crear tu plan personalizado. ¡Un momento!';
    } else {
      errorMessage = 'Escribe "confirmar" para guardar tu perfil o dime qué datos deseas corregir.';
    }
    break;

  default:
    isValid = true;
    nextQuestion = '';
}

if (isValid && fieldName) {
  state.data[fieldName] = fieldValue;
  state.step = state.step + 1;
  state.lastUpdated = new Date().toISOString();
}

const isComplete = state.step > 16;

return [{
  json: {
    state,
    isValid,
    isComplete,
    responseMessage: isValid ? nextQuestion : errorMessage
  }
}];

const data = $json.state.data;

// Mifflin-St Jeor Equation
let bmr;
if (data.gender === 'male') {
  bmr = (10 * data.weight_kg) + (6.25 * data.height_cm) - (5 * data.age) + 5;
} else {
  bmr = (10 * data.weight_kg) + (6.25 * data.height_cm) - (5 * data.age) - 161;
}

// Activity multipliers
const activityMultipliers = {
  'sedentary': 1.2,
  'lightly_active': 1.375,
  'moderately_active': 1.55,
  'very_active': 1.725,
  'extra_active': 1.9
};

const tdee = bmr * (activityMultipliers[data.activity_level] || 1.2);

// Caloric target based on goal
let caloricTarget;
switch (data.goal) {
  case 'lose_weight': caloricTarget = tdee - 500; break;
  case 'gain_muscle': caloricTarget = tdee + 300; break;
  case 'maintain': caloricTarget = tdee; break;
  case 'recomposition': caloricTarget = tdee - 100; break;
  default: caloricTarget = tdee;
}

// Macronutrient targets
const proteinTarget = data.weight_kg * (data.goal === 'gain_muscle' ? 2.2 : 1.8);
const fatTarget = (caloricTarget * 0.25) / 9;
const carbTarget = (caloricTarget - (proteinTarget * 4) - (fatTarget * 9)) / 4;

const trigger = $('Execute Workflow Trigger').first().json;

return [{
  json: {
    ...data,
    bmr: Math.round(bmr * 100) / 100,
    tdee: Math.round(tdee * 100) / 100,
    caloric_target: Math.round(caloricTarget * 100) / 100,
    protein_target_g: Math.round(proteinTarget * 10) / 10,
    carb_target_g: Math.round(carbTarget * 10) / 10,
    fat_target_g: Math.round(fatTarget * 10) / 10,
    userId: trigger.userId,
    telegramId: trigger.telegramId,
    chatId: trigger.chatId,
    firstName: trigger.firstName
  }
}];
